const input = items[0].json;

// Parse the JSON string inside stdout
let data = {};
try {
  data = JSON.parse(input.stdout || '{}');
} catch (e) {
  console.error("Failed to parse invoice output");
}

return [{
  json: {
    payment_request: data.payment_request || "",
    r_hash: data.r_hash || "",
    add_index: data.add_index || "",
    raw_stdout: input.stdout
  }
}];;

// Parse Payment Result
const text = items[0].json.stdout || '';

// === Status (get the LAST occurrence) ===
const statusMatches = text.match(/Payment status:\s*(SUCCEEDED|IN_FLIGHT|FAILED|UNKNOWN)/gi);
let finalStatus = 'UNKNOWN';

if (statusMatches && statusMatches.length > 0) {
  // Take the last match and extract only the status word
  const lastMatch = statusMatches[statusMatches.length - 1];
  const statusWord = lastMatch.match(/(SUCCEEDED|IN_FLIGHT|FAILED|UNKNOWN)/i);
  if (statusWord) finalStatus = statusWord[1].toUpperCase();
}

// === Amount ===
let finalAmount = 0;
const amountLineMatch = text.match(/Amount \+ fee:\s*(\d+)/gi);
if (amountLineMatch && amountLineMatch.length > 0) {
  const lastLine = amountLineMatch[amountLineMatch.length - 1];
  const numMatch = lastLine.match(/(\d+)/);
  if (numMatch) finalAmount = parseInt(numMatch[1]);
}

if (finalAmount === 0) {
  const receiverMatch = text.match(/RECEIVER_AMT\s*\|\s*(\d+)/i);
  if (receiverMatch) finalAmount = parseInt(receiverMatch[1]);
}

// === Hash & Preimage ===
const hashMatch = text.match(/Payment hash:\s*([a-f0-9]+)/i);
const preimageMatch = text.match(/preimage:\s*([a-f0-9]+)/i);

return [{
  json: {
    success: finalStatus === "SUCCEEDED",
    status: finalStatus,
    amount: finalAmount,
    payment_fee: 0,
    payment_hash: hashMatch ? hashMatch[1] : "N/A",
    preimage: preimageMatch ? preimageMatch[1] : null,
    raw_stdout: text.substring(0, 700)
  }
}];

